  "inlineSchema": "// ============================================\n// OrdenaTEC — Prisma Schema\n// Defines the data model for the e-commerce\n// PC configurator platform.\n// ============================================\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ---- Enums ----\n\n/// Roles de usuario en la plataforma\nenum Rol {\n  CLIENTE\n  ADMIN\n}\n\n/// Tipos de componentes de PC\nenum TipoComponente {\n  CPU\n  MOTHERBOARD\n  RAM\n  GPU\n  ALMACENAMIENTO\n  PSU\n  GABINETE\n}\n\n/// Estados posibles de un pedido\nenum EstadoPedido {\n  PENDIENTE\n  PAGADO\n  ENVIADO\n  ENTREGADO\n  CANCELADO\n}\n\n/// Estados posibles de un pago\nenum EstadoPago {\n  PENDIENTE\n  COMPLETADO\n  FALLIDO\n  REEMBOLSADO\n}\n\n// ---- Models ----\n\n/// Usuario registrado en la plataforma\nmodel Usuario {\n  id              String          @id @default(uuid())\n  email           String          @unique\n  nombre          String\n  password        String // Hash bcrypt\n  rol             Rol             @default(CLIENTE)\n  configuraciones Configuracion[]\n  pedidos         Pedido[]\n  createdAt       DateTime        @default(now())\n  updatedAt       DateTime        @updatedAt\n\n  @@map(\"usuarios\")\n}\n\n/// Componente de PC disponible en el catálogo\nmodel Componente {\n  id              String                    @id @default(uuid())\n  sku             String                    @unique\n  nombre          String\n  tipo            TipoComponente\n  precio          Float\n  stock           Int                       @default(0)\n  atributos       Json // Atributos dinámicos según tipo\n  imagenUrl       String?\n  activo          Boolean                   @default(true)\n  configuraciones ConfiguracionComponente[]\n  createdAt       DateTime                  @default(now())\n  updatedAt       DateTime                  @updatedAt\n\n  @@index([tipo])\n  @@index([activo])\n  @@map(\"componentes\")\n}\n\n/// Configuración de PC armada por el usuario\nmodel Configuracion {\n  id              String                    @id @default(uuid())\n  nombre          String?\n  usuarioId       String?\n  usuario         Usuario?                  @relation(fields: [usuarioId], references: [id])\n  precioTotal     Float                     @default(0)\n  consumoEstimado Float? // Watts estimados\n  componentes     ConfiguracionComponente[]\n  pedidos         Pedido[]\n  createdAt       DateTime                  @default(now())\n  updatedAt       DateTime                  @updatedAt\n\n  @@map(\"configuraciones\")\n}\n\n/// Tabla intermedia: relación muchos-a-muchos entre Configuracion y Componente\nmodel ConfiguracionComponente {\n  configuracionId String\n  componenteId    String\n  configuracion   Configuracion @relation(fields: [configuracionId], references: [id], onDelete: Cascade)\n  componente      Componente    @relation(fields: [componenteId], references: [id], onDelete: Cascade)\n\n  @@id([configuracionId, componenteId])\n  @@map(\"configuracion_componentes\")\n}\n\n/// Pedido realizado por un usuario\nmodel Pedido {\n  id              String         @id @default(uuid())\n  usuarioId       String\n  usuario         Usuario        @relation(fields: [usuarioId], references: [id])\n  configuracionId String?\n  configuracion   Configuracion? @relation(fields: [configuracionId], references: [id])\n  estado          EstadoPedido   @default(PENDIENTE)\n  total           Float\n  direccionEnvio  String?\n  pagos           Pago[]\n  createdAt       DateTime       @default(now())\n  updatedAt       DateTime       @updatedAt\n\n  @@map(\"pedidos\")\n}\n\n/// Registro de pago asociado a un pedido\nmodel Pago {\n  id       String     @id @default(uuid())\n  pedidoId String\n  pedido   Pedido     @relation(fields: [pedidoId], references: [id])\n  monto    Float\n  metodo   String // \"tarjeta\", \"transferencia\", \"simulado\"\n  estado   EstadoPago @default(PENDIENTE)\n  fecha    DateTime   @default(now())\n\n  @@map(\"pagos\")\n}\n",
